'use client';

import React, { useState } from 'react';

interface FieldTypesProps {
  data: {
    tabs: Array<{
      id: string;
      label: string;
      title: string;
      description: string;
      features: string[];
    }>;
  };
  style?: any;
}

export default function FieldTypesSection({ data }: FieldTypesProps) {
  const [activeTab, setActiveTab] = useState(data.tabs[0]?.id || '');
  const activeTabData = data.tabs.find(tab => tab.id === activeTab) || data.tabs[0];

  return (
    <section className="mx-auto max-w-7xl px-6 py-16 grid lg:grid-cols-[280px_1fr] gap-10">
      <aside>
        <div className="rounded-2xl bg-white dark:bg-white/5 border border-slate-200 dark:border-white/10 p-4 shadow-sm">
          {data.tabs.map((tab, index) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`w-full text-left px-3 py-2 rounded-lg mb-2 transition-colors ${
                activeTab === tab.id 
                  ? 'bg-violet-100 text-violet-800 dark:bg-white/10 dark:text-white' 
                  : 'hover:bg-slate-50 dark:hover:bg-white/10 text-slate-700 dark:text-slate-300'
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </aside>
      <div className="rounded-2xl bg-white dark:bg-white/5 border border-slate-200 dark:border-white/10 p-6 shadow-sm">
        <h2 className="text-3xl font-bold text-slate-900 dark:text-white">{activeTabData.title}</h2>
        <p className="mt-2 text-slate-600 dark:text-slate-300">{activeTabData.description}</p>
        <ul className="mt-4 grid sm:grid-cols-2 gap-3 text-sm">
          {activeTabData.features.map((feature, index) => {
            const colors = [
              'bg-blue-50 border-blue-200 text-blue-800',
              'bg-emerald-50 border-emerald-200 text-emerald-800',
              'bg-violet-50 border-violet-200 text-violet-800',
              'bg-cyan-50 border-cyan-200 text-cyan-800',
              'bg-amber-50 border-amber-200 text-amber-800',
              'bg-rose-50 border-rose-200 text-rose-800',
              'bg-indigo-50 border-indigo-200 text-indigo-800',
              'bg-teal-50 border-teal-200 text-teal-800'
            ];
            return (
              <li key={index} className={`p-3 rounded-lg border hover:shadow-sm transition-colors dark:bg-white/5 dark:border-white/10 dark:hover:bg-white/10 dark:text-slate-300 ${colors[index % colors.length]}`}>
                {feature}
              </li>
            );
          })}
        </ul>
      </div>
    </section>
  );
}